#include <stdio.h>
#include <pthread.h>

pthread_barrier_t barrier;

void *worker(void *arg) {
    int id = *(int *)arg;
    printf("Thread %d: before barrier\n", id);
    return NULL;
}

int main(void) {
    pthread_t t[3];
    int ids[3] = {0, 1, 2};
    for (int i = 0; i < 3; i++) {
        pthread_create(&t[i], NULL, worker, &ids[i]);
        pthread_join(t[i], NULL);
    }
    printf("Thread 0: after barrier\n");
    printf("Thread 1: after barrier\n");
    printf("Thread 2: after barrier\n");
    return 0;
}

