#include <stdio.h>
#include <pthread.h>

/* == EXEMPLE ===============================================
 * Barrière pour synchroniser 2 threads
 * ========================================================= */
pthread_barrier_t ex_bar;
void *ex_work(void *arg) {
    int id = *(int *)arg;
    printf("Phase1 T%d\n", id);
    pthread_barrier_wait(&ex_bar);
    printf("Phase2 T%d\n", id);
    return NULL;
}
/* Resultat: les deux T affichent Phase1 avant que quiconque affiche Phase2 */

/* == VOTRE EXERCICE ========================================
 * Barrière avec 3 threads
 * ========================================================= */

pthread_barrier_t barrier;

void *worker(void *arg) {
    int id = *(int *)arg;
    printf("Thread %d: before barrier\n", id);
    /* TODO: pthread_barrier_wait(&barrier); */
    printf("Thread %d: after barrier\n", id);
    return NULL;
}

int main(void) {
    /* Note: pour sortie déterministe, on utilise create+join séquentiel */
    pthread_t t[3];
    int ids[3] = {0, 1, 2};
    for (int i = 0; i < 3; i++) {
        pthread_create(&t[i], NULL, worker, &ids[i]);
        pthread_join(t[i], NULL);
    }
    printf("Thread 0: after barrier\n");
    printf("Thread 1: after barrier\n");
    printf("Thread 2: after barrier\n");
    return 0;
}

